from datetime import datetime
from odoo.exceptions import UserError
# Move task to Rejected if deadline is exceeded
for task in records:
    if task.date_deadline:
        today = datetime.now().date()
        if today > task.date_deadline.date() and task.custom_stage != 'approved':
            task.custom_stage = 'rejected'
            # Send notification
            task.message_post(body='Task automatically moved to Rejected due to deadline.')

from odoo.exceptions import UserError
# Validate that PR link exists before moving to Approved
for task in records:
    if task.custom_stage == 'approved' and not task.github_pr_link:
        raise UserError('GitHub PR link is required to move to Approved status.')

from odoo.exceptions import UserError
# Ensure reviewer is assigned before task approval
for task in records:
    if task.custom_stage in ['in_review', 'approved'] and not task.reviewer_id:
        raise UserError('Reviewer (Tech Lead) must be assigned before review can proceed.')
